import React from 'react';

function TableTemplate({ data, columns, entityIdKey, onEdit, onDelete }) {
      const tableContainerStyles = {
        background: 'rgba(255, 255, 255, 0.95)',
        backdropFilter: 'blur(20px)',
        borderRadius: '20px',
        padding: '30px',
        margin: '20px 0',
        boxShadow: '0 10px 40px rgba(0,0,0,0.15)',
        border: '1px solid rgba(255, 255, 255, 0.3)',
        overflow: 'hidden',
      };

      const headerStyles = {
        fontSize: '1.2rem',
        fontWeight: '600',
        color: '#2c3e50',
        marginBottom: '15px',
        textAlign: 'center',
        background: 'linear-gradient(135deg, #e74c3c, #c0392b)',
        WebkitBackgroundClip: 'text',
        WebkitTextFillColor: 'transparent',
        backgroundClip: 'text',
        borderBottom: '2px solid #e74c3c',
        paddingBottom: '8px',
      };

  const noDataStyles = {
    textAlign: 'center',
    padding: '40px',
    color: '#666',
    fontSize: '1.1rem',
    background: 'rgba(102, 126, 234, 0.1)',
    borderRadius: '10px',
    border: '2px dashed rgba(102, 126, 234, 0.3)',
  };

  const tableStyles = {
    width: '100%',
    borderCollapse: 'separate',
    borderSpacing: '0',
    borderRadius: '10px',
    overflow: 'hidden',
    boxShadow: '0 4px 15px rgba(0,0,0,0.1)',
  };

      const thStyles = {
        background: 'linear-gradient(135deg, #11998e 0%, #38ef7d 100%)',
        color: 'white',
        padding: '15px 12px',
        textAlign: 'left',
        fontWeight: '600',
        fontSize: '0.85rem',
        textTransform: 'uppercase',
        letterSpacing: '0.5px',
        borderBottom: 'none',
      };

  const tdStyles = {
    padding: '15px 12px',
    borderBottom: '1px solid rgba(0,0,0,0.05)',
    background: 'transparent',
    transition: 'all 0.3s ease',
  };

  const trStyles = {
    transition: 'all 0.3s ease',
  };

      const actionButtonStyles = {
        background: 'linear-gradient(135deg, #11998e 0%, #38ef7d 100%)',
        color: 'white',
        border: 'none',
        padding: '8px 16px',
        borderRadius: '12px',
        fontSize: '0.8rem',
        fontWeight: '600',
        cursor: 'pointer',
        marginRight: '8px',
        transition: 'all 0.3s ease',
        boxShadow: '0 4px 12px rgba(17, 153, 142, 0.3)',
      };

      const deleteButtonStyles = {
        background: 'linear-gradient(135deg, #fa709a 0%, #fee140 100%)',
        color: 'white',
        border: 'none',
        padding: '8px 16px',
        borderRadius: '12px',
        fontSize: '0.8rem',
        fontWeight: '600',
        cursor: 'pointer',
        transition: 'all 0.3s ease',
        boxShadow: '0 4px 12px rgba(250, 112, 154, 0.3)',
      };

  if (!data || data.length === 0) {
    return (
      <div style={tableContainerStyles}>
        <h3 style={headerStyles}>📊 All Records</h3>
        <div style={noDataStyles}>
          <div style={{ fontSize: '3rem', marginBottom: '15px' }}>📭</div>
          <div>No records found.</div>
          <div style={{ fontSize: '0.9rem', marginTop: '10px', opacity: 0.7 }}>
            Add some records to see them here!
          </div>
        </div>
      </div>
    );
  }

  return (
    <div style={tableContainerStyles}>
      <h3 style={headerStyles}>📊 All Records ({data.length})</h3>
      <table style={tableStyles}>
        <thead>
          <tr>
            {columns.map(col => (
              <th key={col.key} style={thStyles}>
                {col.header}
              </th>
            ))}
            <th style={thStyles}>Actions</th>
          </tr>
        </thead>
        <tbody>
          {data.map((item, index) => (
            <tr 
              key={item[entityIdKey]} 
              style={{
                ...trStyles,
                background: index % 2 === 0 ? 'rgba(255,255,255,0.8)' : 'rgba(248,249,250,0.8)',
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.background = 'rgba(17, 153, 142, 0.1)';
                e.currentTarget.style.transform = 'translateY(-4px)';
                e.currentTarget.style.boxShadow = '0 8px 25px rgba(17, 153, 142, 0.15)';
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.background = index % 2 === 0 ? 'rgba(255,255,255,0.8)' : 'rgba(248,249,250,0.8)';
                e.currentTarget.style.transform = 'translateY(0)';
                e.currentTarget.style.boxShadow = 'none';
              }}
            >
              {columns.map(col => (
                <td key={col.key} style={tdStyles}>
                  {item[col.key] === null || item[col.key] === undefined ? (
                    <span style={{ color: '#999', fontStyle: 'italic' }}>N/A</span>
                  ) : (
                    item[col.key]
                  )}
                </td>
              ))}
              <td style={tdStyles}>
                <button 
                  onClick={() => onEdit(item)} 
                  style={actionButtonStyles}
                  onMouseEnter={(e) => {
                    e.target.style.transform = 'translateY(-2px) scale(1.05)';
                    e.target.style.boxShadow = '0 8px 25px rgba(17, 153, 142, 0.5)';
                  }}
                  onMouseLeave={(e) => {
                    e.target.style.transform = 'translateY(0) scale(1)';
                    e.target.style.boxShadow = '0 4px 12px rgba(17, 153, 142, 0.3)';
                  }}
                >
                  ✏️ Edit
                </button>
                <button 
                  onClick={() => onDelete(item[entityIdKey])} 
                  style={deleteButtonStyles}
                  onMouseEnter={(e) => {
                    e.target.style.transform = 'translateY(-2px) scale(1.05)';
                    e.target.style.boxShadow = '0 8px 25px rgba(250, 112, 154, 0.5)';
                  }}
                  onMouseLeave={(e) => {
                    e.target.style.transform = 'translateY(0) scale(1)';
                    e.target.style.boxShadow = '0 4px 12px rgba(250, 112, 154, 0.3)';
                  }}
                >
                  🗑️ Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default TableTemplate;
